                            "tier": "junior",
                            "code": "// === JUNIOR EXAMPLE ===\n// TASK      - Real-world usage of Testing Patterns — AAA, Factories, Builders — common patterns you'll see in production.\n// APPROACH  - Combine Testing Patterns — AAA, Factories, Builders with related functions; handle common edge cases.\n// STRENGTHS - Practical; covers the 80% use cases encountered on the job.\n// WEAKNESSES- May need optimization for large datasets or complex queries.\n// APPROACH  - the three test-organization patterns: AAA structure, factory\n//             functions with overrides, and the builder for fluent composition.\n// STRENGTHS - the 80% case — tests read top-to-bottom, test data stops being\n//             noisy, and builders make complex object setup declarative.\n// WEAKNESSES- builders add class boilerplate for simple objects; factories with\n//             too many overrides hint the data model is too coupled to tests.\n//\n// GOAL: structure tests and build clean test data\n// WHY: AAA reveals intent; factories/builders remove noise from the real assertion\n// ── AAA Pattern (Arrange-Act-Assert) ──────────────────\ndescribe('calculateTotal', () => {\n  it('calculates sum with tax', () => {\n    // ARRANGE: setup test data and dependencies\n    const items = [\n      { id: 1, price: 10, quantity: 2 },\n      { id: 2, price: 5, quantity: 3 },\n    ];\n    const taxRate = 0.1;\n    // ACT: call the function\n    const total = calculateTotal(items, taxRate);\n    // ASSERT: verify the result\n    expect(total).toBe(38.5); // (20+15) * 1.1\n  });\n});\n// ── Test Factory (function returning test object) ──────\nfunction createUser(overrides = {}) {\n  return {\n    id: 1,\n    name: 'Alice',\n    email: 'alice@test.com',\n    role: 'user',\n    createdAt: new Date('2024-01-01'),\n    ...overrides,\n  };\n}\nit('admin users can delete', () => {\n  // Quick setup with factory\n  const admin = createUser({ role: 'admin' });\n  const user = createUser({ role: 'user' });\n  expect(canDelete(admin)).toBe(true);\n  expect(canDelete(user)).toBe(false);\n});\n// ── Builder Pattern (fluent API) ──────────────────────\nclass UserBuilder {\n  private data = {\n    id: 1,\n    name: 'Alice',\n    email: 'alice@test.com',\n    role: 'user' as const,\n    verified: false,\n  };\n  withRole(role: string) {\n    this.data.role = role as any;\n    return this;\n  }\n  withEmail(email: string) {\n    this.data.email = email;\n    return this;\n  }\n  verified() {\n    this.data.verified = true;\n    return this;\n  }\n  build() {\n    return { ...this.data };\n  }\n}\nit('verified admins bypass moderation', () => {\n  const user = new UserBuilder()\n    .withRole('admin')\n    .verified()\n    .build();\n  expect(user.role).toBe('admin');\n  expect(user.verified).toBe(true);\n});\n// ── Combining Factory + Builder ────────────────────────\nfunction createUserBuilder(overrides = {}) {\n  const user = createUser(overrides);\n  return new UserBuilder()\n    .withEmail(user.email)\n    .withRole(user.role);\n}\n// ── Test data generator (complex scenarios) ──────────\nfunction createPost(overrides = {}) {\n  return {\n    id: Math.random(),\n    title: 'Sample Post',\n    content: 'Lorem ipsum...',\n    authorId: 1,\n    published: true,\n    likes: 0,\n    ...overrides,\n  };\n}\nfunction createComment(overrides = {}) {\n  return {\n    id: Math.random(),\n    postId: 1,\n    userId: 1,\n    text: 'Great post!',\n    createdAt: new Date(),\n    ...overrides,\n  };\n}\nit('post with comments', () => {\n  const post = createPost({ id: 1 });\n  const comments = [\n    createComment({ postId: 1, text: 'First!' }),\n    createComment({ postId: 1, text: 'Nice work' }),\n  ];\n  expect(comments.length).toBe(2);\n  expect(comments[0].postId).toBe(post.id);\n});"
